import jwt from 'jsonwebtoken';

import type { Request, Response, NextFunction } from 'express';
import { HTTP_STATUS, ERROR_CODE, AUTH } from '../config/constants';
import { env } from '../config/env';
import { prisma } from '../lib/prisma';
import { AppError } from '../utils/app-error';
import { asyncHandler } from '../utils/async-handler';


interface JwtPayload {
  userId: string;
  email: string;
}

export const requireAuth = asyncHandler(async (req: Request, res: Response, next: NextFunction) => {
  const authHeader = req.headers.authorization;

  if (!authHeader?.startsWith(AUTH.ACCESS_TOKEN_PREFIX)) {
    throw new AppError('Unauthorized', HTTP_STATUS.UNAUTHORIZED, ERROR_CODE.UNAUTHORIZED);
  }

  const token = authHeader.split(' ')[1];

  try {
    const decoded = jwt.verify(token, env.JWT_ACCESS_SECRET) as JwtPayload;

    // Verify user still exists
    const user = await prisma.user.findUnique({
      where: { id: decoded.userId },
      select: { id: true, email: true, deleted_at: true },
    });

    if (!user || user.deleted_at) {
      throw new AppError(
        'User no longer exists',
        HTTP_STATUS.UNAUTHORIZED,
        ERROR_CODE.UNAUTHORIZED,
      );
    }

    req.user = {
      id: user.id,
      email: user.email,
    };

    next();
  } catch (error) {
    if (error instanceof jwt.TokenExpiredError) {
      throw new AppError('Token expired', HTTP_STATUS.UNAUTHORIZED, ERROR_CODE.UNAUTHORIZED);
    }
    throw new AppError('Invalid token', HTTP_STATUS.UNAUTHORIZED, ERROR_CODE.UNAUTHORIZED);
  }
});

import type { Request, Response, NextFunction } from 'express';
import { HTTP_STATUS, ERROR_CODE } from '../config/constants';
import { logger } from '../lib/logger';
import { ApiResponse } from '../utils/api-response';
import { AppError } from '../utils/app-error';


export const errorHandler = (
  err: Error,
  req: Request,
  res: Response,
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  next: NextFunction,
) => {
  // Operational errors (AppError)
  if (err instanceof AppError) {
    return ApiResponse.error(res, err.statusCode, err.message, {
      code: err.code,
    });
  }

  // Prisma errors (unique constraint violation, etc.)
  if (err.name === 'PrismaClientKnownRequestError') {
    // @ts-expect-error - Prisma error typing
    if (err.code === 'P2002') {
      return ApiResponse.error(
        res,
        HTTP_STATUS.CONFLICT,
        'A record with this value already exists',
        { code: ERROR_CODE.CONFLICT },
      );
    }
  }

  // Unexpected errors
  logger.error(
    {
      err,
      req: {
        id: req.id,
        method: req.method,
        url: req.url,
        body: req.body,
      },
    },
    'Unhandled Error',
  );

  return ApiResponse.error(res, HTTP_STATUS.INTERNAL_SERVER_ERROR, 'Internal Server Error', {
    code: ERROR_CODE.INTERNAL_ERROR,
  });
};

import { ZodError } from 'zod';

import type { Request, Response, NextFunction } from 'express';
import type { ZodObject} from 'zod';
import { HTTP_STATUS, ERROR_CODE } from '../config/constants';
import { ApiResponse } from '../utils/api-response';


export const validate = (schema: ZodObject<import("zod").ZodRawShape>) => {
  return async (req: Request, res: Response, next: NextFunction) => {
    try {
      const parsed = await schema.parseAsync({
        body: req.body,
        query: req.query,
        params: req.params,
      });

      // Update request properties safely for Express 5 getters
      req.body = parsed.body;

      // Object.assign to avoid 'Cannot set property query... which has only a getter'
      for (const key in req.query) {delete req.query[key as keyof typeof req.query];}
      Object.assign(req.query, parsed.query || {});

      for (const key in req.params) {delete req.params[key];}
      Object.assign(req.params, parsed.params || {});

      next();
    } catch (error) {
      if (error instanceof ZodError) {
        const formattedErrors = error.issues.map((e: import('zod').ZodIssue) => ({
          field: e.path.join('.'),
          message: e.message,
        }));

        return ApiResponse.error(res, HTTP_STATUS.UNPROCESSABLE_ENTITY, 'Validation failed', {
          code: ERROR_CODE.VALIDATION_ERROR,
          errors: formattedErrors,
        });
      }
      next(error);
    }
  };
