import { prisma } from '../lib/prisma';

export interface DailyAvailability {
  is_available: boolean;
  start_time: string | null;
  end_time: string | null;
  timezone: string;
}

export class AvailabilityService {
  /**
   * Helper for the slot calculator: returns the exact availability rules for a specific date
   */
  static async getAvailabilityForDate(userId: string, date: Date, scheduleId?: string): Promise<DailyAvailability | null> {
    let schedule;

    if (scheduleId) {
      schedule = await prisma.schedule.findUnique({
        where: { id: scheduleId, user_id: userId },
        include: { availability: true, overrides: true },
      });
    } else {
      // Fallback to default schedule
      schedule = await prisma.schedule.findFirst({
        where: { user_id: userId, is_default: true },
        include: { availability: true, overrides: true },
      });
    }

    if (!schedule) {
      return null;
    }

    // 1. Check Date Overrides first (midnight UTC matching)
    const override = schedule.overrides.find((o) => o.date.getTime() === date.getTime());
    if (override) {
      return {
        is_available: override.is_available,
        start_time: override.start_time,
        end_time: override.end_time,
        timezone: schedule.timezone,
      };
    }

    // 2. Check standard weekly availability (day of week: 0 = Sunday, 1 = Monday)
    const dayOfWeek = date.getDay();
    const standard = schedule.availability.find((a) => a.day_of_week === dayOfWeek && a.is_active);

    if (standard) {
      return {
        is_available: true,
        start_time: standard.start_time,
        end_time: standard.end_time,
        timezone: schedule.timezone,
      };
    }

    // 3. No availability found for this day
    return {
      is_available: false,
      start_time: null,
      end_time: null,
      timezone: schedule.timezone,
    };
  }
}

import type { Booking, EventType, User } from '@prisma/client';
import type { CreateBookingInput, UpdateBookingStatusInput } from '@scaler/types';
import { ERROR_CODE, HTTP_STATUS, BOOKING_STATUS } from '../config/constants';
import { eventBus, EVENTS } from '../lib/event-bus';
import { logger } from '../lib/logger';
import { prisma } from '../lib/prisma';
import { AppError } from '../utils/app-error';
import { OverlapUtils } from '../utils/overlap';


export type BookingWithRelations = Booking & {
  event_type: EventType;
};

export type FullBookingWithRelations = Booking & {
  event_type: EventType;
  host: User;
};


export class BookingService {
  static async getBookings(userId: string): Promise<BookingWithRelations[]> {
    return prisma.booking.findMany({
      where: { host_id: userId },
      include: {
        event_type: true,
      },
      orderBy: { start_time: 'desc' },
    });
  }

  static async getBookingById(userId: string, id: string): Promise<BookingWithRelations> {
    const booking = await prisma.booking.findUnique({
      where: { id },
      include: { event_type: true },
    });

    if (!booking || booking.host_id !== userId) {
      throw new AppError('Booking not found', HTTP_STATUS.NOT_FOUND, ERROR_CODE.NOT_FOUND);
    }

    return booking;
  }

  /**
   * Core transactional booking logic ensuring double-booking prevention via row-level locks
   */
  static async createBooking(data: CreateBookingInput): Promise<FullBookingWithRelations> {
    const eventType = await prisma.eventType.findUnique({
      where: { id: data.event_type_id },
      include: { user: true },
    });

    if (!eventType || !eventType.is_active || eventType.deleted_at) {
      throw new AppError('Event type not available', HTTP_STATUS.NOT_FOUND, ERROR_CODE.NOT_FOUND);
    }

    const startTime = new Date(data.start_time);
    const endTime = new Date(data.end_time);

    // 1. Transaction to prevent double booking
    const booking = await prisma.$transaction(async (tx) => {
      // Row-level lock using raw SQL to prevent race conditions during slot claiming
      const overlapping: { id: string }[] = await tx.$queryRaw(
        OverlapUtils.getOverlapQuery(eventType.user_id, startTime, endTime),
      );

      if (overlapping.length > 0) {
        throw new AppError(
          'This time slot has already been booked',
          HTTP_STATUS.CONFLICT,
          ERROR_CODE.CONFLICT,
        );
      }

      // Status depends on event type settings
      const status = eventType.requires_confirmation
        ? BOOKING_STATUS.PENDING
        : BOOKING_STATUS.CONFIRMED;

      // Mock meeting URL generation (ideally this would be generated by Zoom/Google Meet Integration Service)
      let meetingUrl = null;
      if (eventType.location_type === 'GOOGLE_MEET')
        {meetingUrl = 'https://meet.google.com/mock-url';}
      if (eventType.location_type === 'ZOOM') {meetingUrl = 'https://zoom.us/j/mock-id';}

      // Create booking record
      return tx.booking.create({
        data: {
          event_type_id: eventType.id,
          host_id: eventType.user_id,
          guest_name: data.guest_name,
          guest_email: data.guest_email,
          guest_notes: data.guest_notes,
          start_time: startTime,
          end_time: endTime,
          status,
          meeting_url: meetingUrl,
        },
        include: {
          event_type: true,
          host: true,
        },
      });
    });

    // 2. Dispatch Post-Booking Actions asynchronously via Event Bus
    if (booking.status === BOOKING_STATUS.CONFIRMED) {
      eventBus.emit(EVENTS.BOOKING_CREATED, { booking, timezone: data.timezone });
    }

    return booking;
  }

  static async updateBookingStatus(
    userId: string,
    id: string,
    data: UpdateBookingStatusInput,
    hostTimezone: string,
  ): Promise<Booking> {
    const booking = await this.getBookingById(userId, id);

    // Fetch full relations for notifications
    const fullBooking = await prisma.booking.findUniqueOrThrow({
      where: { id },
      include: { event_type: true, host: true },
    });

    const updated = await prisma.booking.update({
      where: { id },
      data: {
        status: data.status,
        cancellation_reason: data.cancellation_reason,
      },
    });

    // Handle notifications
    if (data.status === BOOKING_STATUS.CANCELLED && booking.status !== BOOKING_STATUS.CANCELLED) {
      // Pass fullBooking and indicate it was cancelled by the host
      eventBus.emit(EVENTS.BOOKING_CANCELLED, {
        booking: {
          ...fullBooking,
          status: data.status,
          cancellation_reason: data.cancellation_reason ?? null,
        },
        timezone: hostTimezone,
        isHost: true,
      });
    } else if (
      data.status === BOOKING_STATUS.CONFIRMED &&
      booking.status === BOOKING_STATUS.PENDING
    ) {
      eventBus.emit(EVENTS.BOOKING_CREATED, {
        booking: { ...fullBooking, status: data.status },
        timezone: hostTimezone
      });
    }

    return updated;
  }
}

import { logger } from '../lib/logger';
import { prisma } from '../lib/prisma';
import { CalendarProviderFactory } from '../lib/providers/calendar-provider.factory';
import { decrypt } from '../utils/encryption';

import type { BookingWithRelations } from '../lib/providers/calendar-provider.interface';

export class CalendarService {
  /**
   * Dispatch calendar creation event to all connected calendar providers for the host
   */
  static async createCalendarEvent(booking: BookingWithRelations): Promise<unknown> {
    try {
      const credentials = await prisma.credential.findMany({
        where: { user_id: booking.host_id },
        include: { app: true },
      });

      if (credentials.length === 0) {
        return; // No connected calendars
      }

      // We wrap calendar dispatches in a Promise.allSettled so one failure doesn't block others
      const promises = credentials.map(async (cred) => {
        const token = decrypt(cred.access_token_encrypted);
        const provider = CalendarProviderFactory.getProvider(cred.app.slug);

        if (!provider) {
          return;
        }

        try {
          return await provider.createEvent(token, booking);
        } catch (error) {
          // Wrap provider errors so they can be processed by Promise.allSettled
          throw { error, app: cred.app.slug };
        }
      });

      const results = await Promise.allSettled(promises);

      // Log failures and record them in the FailedJob table for retry
      results.forEach((result, index) => {
        if (result.status === 'rejected') {
          const appSlug = credentials[index].app.slug;
          logger.error(
            { err: result.reason },
            `Failed to sync calendar event to ${appSlug}`,
          );

          // Fire and forget: log to database
          prisma.failedJob.create({
            data: {
              type: 'CALENDAR_SYNC',
              payload: JSON.stringify({ bookingId: booking.id, appSlug }),
              error: result.reason?.error?.message || 'Unknown error',
              next_retry_at: new Date(Date.now() + 5 * 60 * 1000), // Retry in 5 mins
            }
          }).catch(err => { logger.error({ err }, 'Failed to record failed job'); });
        }
      });
    } catch (error) {
      logger.error({ err: error }, 'Critical error in CalendarService.createCalendarEvent');
      // Guarantee booking persistence
    }
  }
}

