    await this.getEventTypeById(userId, id);

    if (data.slug) {
      const existing = await prisma.eventType.findUnique({
        where: {
          user_id_slug: {
            user_id: userId,
            slug: data.slug,
          },
        },
      });

      if (existing && existing.id !== id && !existing.deleted_at) {
        throw new AppError(
          'Event type with this slug already exists',
          HTTP_STATUS.CONFLICT,
          ERROR_CODE.CONFLICT,
        );
