  ): Promise<ScheduleWithRelations> {
    // If this is meant to be default, unset other defaults
    if (data.is_default) {
      await prisma.schedule.updateMany({
        where: { user_id: userId, is_default: true },
        data: { is_default: false },
      });
    }

    // Default Monday-Friday 9am-5pm if not provided
    const defaultAvailability = [1, 2, 3, 4, 5].map((day) => ({
      day_of_week: day,
      start_time: '09:00',
      end_time: '17:00',
    }));

    return prisma.schedule.create({
      data: {
        name: data.name,
        timezone: data.timezone,
        is_default: data.is_default,
        user_id: userId,
        availability: {
          create: data.availability ?? defaultAvailability,
        },
      },
      include: {
        availability: true,
        overrides: true,
      },
    });
  }

  static async updateSchedule(
    userId: string,
    id: string,
    data: UpdateScheduleInput,
  ): Promise<ScheduleWithRelations> {
    await this.getScheduleById(userId, id);

    if (data.is_default) {
      await prisma.schedule.updateMany({
        where: { user_id: userId, is_default: true, id: { not: id } },
        data: { is_default: false },
      });
    }

    return prisma.$transaction(async (tx) => {
      // 1. Update basic schedule details
      await tx.schedule.update({
        where: { id },
        data: {
          name: data.name,
          timezone: data.timezone,
          is_default: data.is_default,
        },
      });

      // 2. Overwrite availability if provided
      if (data.availability) {
        await tx.scheduleAvailability.deleteMany({
          where: { schedule_id: id },
        });
        if (data.availability.length > 0) {
          await tx.scheduleAvailability.createMany({
            data: data.availability.map((a) => ({
              schedule_id: id,
              ...a,
            })),
          });
        }
      }

      // 3. Update overrides if provided
      if (data.overrides) {
        await tx.dateOverride.deleteMany({
          where: { schedule_id: id },
        });
        if (data.overrides.length > 0) {
          await tx.dateOverride.createMany({
            data: data.overrides.map((o) => ({
              schedule_id: id,
              date: new Date(o.date),
              start_time: o.start_time,
              end_time: o.end_time,
              is_available: o.is_available,
            })),
          });
        }
      }

      // 4. Return updated record
      return tx.schedule.findUniqueOrThrow({
        where: { id },
        include: {
          availability: true,
          overrides: true,
        },
      });
    });
  }

  static async deleteSchedule(userId: string, id: string): Promise<void> {
    const schedule = await this.getScheduleById(userId, id);

    if (schedule.is_default) {
      throw new AppError(
        'Cannot delete default schedule',
        HTTP_STATUS.BAD_REQUEST,
        ERROR_CODE.VALIDATION_ERROR,
      );
    }

    await prisma.schedule.delete({
      where: { id },
    });
  }
}

import crypto from 'crypto';

import jwt from 'jsonwebtoken';

import type { SignOptions } from 'jsonwebtoken';
import { ERROR_CODE, HTTP_STATUS } from '../config/constants';
import { env } from '../config/env';
import { prisma } from '../lib/prisma';
import { AppError } from '../utils/app-error';


interface TokenPayload {
  userId: string;
  email: string;
}

export class TokenService {
  /**
   * Generates a short-lived access token
   */
  static generateAccessToken(payload: TokenPayload): string {
    return jwt.sign(payload, env.JWT_ACCESS_SECRET, {
      expiresIn: String(env.JWT_ACCESS_EXPIRES_IN) as SignOptions['expiresIn'],
    });
  }

  /**
   * Generates a long-lived refresh token and stores its hash in the database
   */
  static async generateRefreshToken(payload: TokenPayload): Promise<string> {
    const refreshToken = jwt.sign(payload, env.JWT_REFRESH_SECRET, {
      expiresIn: String(env.JWT_REFRESH_EXPIRES_IN) as SignOptions['expiresIn'],
    });

    // Hash the token before saving to database for security
    const tokenHash = crypto.createHash('sha256').update(refreshToken).digest('hex');

    // Parse expiration string (e.g., '7d') to Date object
    const expiresAt = new Date();
    expiresAt.setDate(expiresAt.getDate() + 7); // Defaulting to 7 days to match env fallback

    await prisma.refreshToken.create({
      data: {
        token_hash: tokenHash,
        user_id: payload.userId,
        expires_at: expiresAt,
      },
    });

    return refreshToken;
  }

  /**
   * Verifies a refresh token and issues a new access token
   */
  static async rotateTokens(
    oldRefreshToken: string,
  ): Promise<{ accessToken: string; newRefreshToken: string }> {
    try {
      const decoded = jwt.verify(oldRefreshToken, env.JWT_REFRESH_SECRET) as TokenPayload;
      const tokenHash = crypto.createHash('sha256').update(oldRefreshToken).digest('hex');

      // Check if the token exists and is not revoked
      const storedToken = await prisma.refreshToken.findUnique({
        where: { token_hash: tokenHash },
      });

      if (!storedToken || storedToken.expires_at < new Date()) {
        throw new AppError(
          'Invalid or expired refresh token',
          HTTP_STATUS.UNAUTHORIZED,
          ERROR_CODE.UNAUTHORIZED,
        );
      }

      // TOKEN REUSE DETECTION
      // If a token is already revoked but someone tries to use it, it means the token was likely stolen.
      // We must immediately revoke all tokens for this user.
      if (storedToken.is_revoked) {
        await prisma.refreshToken.updateMany({
          where: { user_id: storedToken.user_id, is_revoked: false },
          data: { is_revoked: true },
        });

        throw new AppError(
          'Token reuse detected. All sessions have been revoked for security.',
          HTTP_STATUS.UNAUTHORIZED,
          ERROR_CODE.UNAUTHORIZED,
        );
      }

      // Revoke the old token (Refresh Token Rotation)
      await prisma.refreshToken.update({
        where: { id: storedToken.id },
        data: { is_revoked: true },
      });

      // Generate new tokens
      const newAccessToken = this.generateAccessToken({
        userId: decoded.userId,
        email: decoded.email,
      });
      const newRefreshToken = await this.generateRefreshToken({
        userId: decoded.userId,
        email: decoded.email,
      });

      return { accessToken: newAccessToken, newRefreshToken };
    } catch (error) {
      if (error instanceof AppError) {
        throw error;
      }
      throw new AppError(
        'Invalid refresh token',
        HTTP_STATUS.UNAUTHORIZED,
        ERROR_CODE.UNAUTHORIZED,
      );
    }
  }

  /**
   * Revokes all refresh tokens for a user (useful for logout everywhere)
   */
  static async revokeAllUserTokens(userId: string): Promise<void> {
    await prisma.refreshToken.updateMany({
      where: { user_id: userId, is_revoked: false },
      data: { is_revoked: true },
    });
  }
}

import type { UpdateUserInput } from '@scaler/types';
import { ERROR_CODE, HTTP_STATUS } from '../config/constants';
import { prisma } from '../lib/prisma';
import { AppError } from '../utils/app-error';


export class UserService {
  static async getCurrentUser(userId: string): Promise<unknown> {
    const user = await prisma.user.findUnique({
      where: { id: userId },
    });

    if (!user || user.deleted_at) {
      throw new AppError('User not found', HTTP_STATUS.NOT_FOUND, ERROR_CODE.NOT_FOUND);
    }

    const safeUser = { ...user };
    delete (safeUser as { password_hash?: string }).password_hash;
    return safeUser;
  }

  static async updateUser(userId: string, data: UpdateUserInput): Promise<unknown> {
    const user = await prisma.user.update({
      where: { id: userId },
      data,
    });

    const safeUser = { ...user };
    delete (safeUser as { password_hash?: string }).password_hash;
    return safeUser;
  }
}

import type { Response } from 'express';

export interface ApiResponseData<T> {
  success: boolean;
  message: string;
  data?: T;
  error?: unknown;
}

export class ApiResponse {
  static send<T>(res: Response, statusCode: number, message: string, data?: T): Response {
    return res.status(statusCode).json({
      success: statusCode >= 200 && statusCode < 300,
      message,
      data,
    });
  }

  static success<T>(res: Response, message = 'Success', data?: T): Response {
    return this.send(res, 200, message, data);
  }

  static created<T>(res: Response, message = 'Created successfully', data?: T): Response {
    return this.send(res, 201, message, data);
  }

  static error(res: Response, statusCode: number, message: string, error?: unknown): Response {
    return res.status(statusCode).json({
      success: false,
      message,
      error,
    });
  }
}

export class AppError extends Error {
  public readonly statusCode: number;
  public readonly isOperational: boolean;
  public readonly code?: string;

  constructor(message: string, statusCode: number, code?: string, isOperational = true) {
    super(message);
    this.statusCode = statusCode;
    this.code = code;
    this.isOperational = isOperational;

    Object.setPrototypeOf(this, new.target.prototype);
    Error.captureStackTrace(this, this.constructor);
  }
}

import crypto from 'crypto';

import { env } from '../config/env';

const ALGORITHM = 'aes-256-gcm';
// ENCRYPTION_KEY must be exactly 32 bytes (64 hex characters)
const ENCRYPTION_KEY = Buffer.from(env.ENCRYPTION_KEY, 'hex');
const IV_LENGTH = 16;
// const AUTH_TAG_LENGTH = 16;

/**
 * Encrypts a plain text string using AES-256-GCM
 * Returns a base64 string formatted as: base64(iv:authTag:encrypted)
 */
export function encrypt(text: string): string {
  const iv = crypto.randomBytes(IV_LENGTH);
  const cipher = crypto.createCipheriv(ALGORITHM, ENCRYPTION_KEY, iv);

  let encrypted = cipher.update(text, 'utf8', 'base64');
  encrypted += cipher.final('base64');

  const authTag = cipher.getAuthTag();

  // Format: iv(base64):authTag(base64):encrypted(base64)
  return `${iv.toString('base64')}:${authTag.toString('base64')}:${encrypted}`;
}

/**
 * Decrypts a base64 string formatted as: base64(iv:authTag:encrypted)
 */
export function decrypt(encryptedData: string): string {
  const parts = encryptedData.split(':');
  if (parts.length !== 3) {
    throw new Error('Invalid encrypted text format');
  }

  const iv = Buffer.from(parts[0], 'base64');
  const authTag = Buffer.from(parts[1], 'base64');
  const encryptedText = parts[2];

  const decipher = crypto.createDecipheriv(ALGORITHM, ENCRYPTION_KEY, iv);
  decipher.setAuthTag(authTag);

  let decrypted = decipher.update(encryptedText, 'base64', 'utf8');
  decrypted += decipher.final('utf8');

  return decrypted;
}

import { isBefore, addMinutes, isAfter } from 'date-fns';

import { BOOKING_STATUS } from '../config/constants';
import { prisma } from '../lib/prisma';
import { AvailabilityService } from '../services/availability.service';
import { DateUtils } from './date';

export interface Slot {
  startTime: string; // ISO string UTC
  endTime: string; // ISO string UTC
  available: boolean;
}

export class SlotCalculator {
  /**
   * Calculates available slots for a given event type on a specific date (YYYY-MM-DD)
   */
  static async getAvailableSlots(
    eventTypeId: string,
    dateStr: string,
    requestedTimeZone: string,
  ): Promise<Slot[]> {
    // 1. Fetch Event Type
    const eventType = await prisma.eventType.findUnique({
      where: { id: eventTypeId },
      include: { user: { include: { schedules: { where: { is_default: true } } } } },
    });

    if (!eventType || eventType.deleted_at !== null || !eventType.is_active) {
      return [];
    }

    const userId = eventType.user_id;

    // We assume the user's default schedule is used for this event type for simplicity,
    // though cal.com allows linking specific schedules to event types.
    // If we wanted to link, we'd add `schedule_id` to `EventType`. Let's use default.
    const defaultScheduleId = eventType.user.schedules[0]?.id;

    // 2. Fetch Availability for the requested date using the host's timezone as base
    // First, we need to know what "dateStr" means. It means the requester wants slots for "2026-06-15" in THEIR timezone.
    // So "2026-06-15T00:00:00" in requestedTimeZone is the start boundary.


    // Get the base availability rule for the host on the UTC date that corresponds to the start of the window
    // This is a slight simplification: technically a requester's single day might span two of the host's days.
    // For robust implementation, we should iterate day by day in the host timezone and generate slots, then filter to requested bounds.
    // Let's generate slots for the host's local day that overlaps most with the requested day.
    // Actually, the simplest correct approach is: fetch availability for the requested date string as if it's the host's date.

    const availability = await AvailabilityService.getAvailabilityForDate(
      userId,
      new Date(dateStr), // Used to get day of week and match overrides
      defaultScheduleId,
    );

    if (
      !availability?.is_available ||
      !availability.start_time ||
      !availability.end_time
    ) {
      return [];
    }

    // 3. Construct UTC boundaries for the host's working hours on this date
    const workStartUTC = DateUtils.parseTimeInTimezone(
      dateStr,
      availability.start_time,
      availability.timezone,
    );
    const workEndUTC = DateUtils.parseTimeInTimezone(
      dateStr,
      availability.end_time,
      availability.timezone,
    );

    // 4. Fetch Existing Bookings
    const bookings = await prisma.booking.findMany({
      where: {
        host_id: userId,
        status: { in: [BOOKING_STATUS.PENDING, BOOKING_STATUS.CONFIRMED] },
        // Fetch all bookings that overlap with this working window
        start_time: { lt: workEndUTC },
        end_time: { gt: workStartUTC },
      },
    });

    // 5. Generate Candidate Slots
    return this.calculatePureSlots({
      dateStr,
      eventType: {
        duration_mins: eventType.duration_mins,
        buffer_before_mins: eventType.buffer_before_mins,
        buffer_after_mins: eventType.buffer_after_mins,
      },
      availability: {
        start_time: availability.start_time,
        end_time: availability.end_time,
        timezone: availability.timezone,
      },
      bookings,
      requestedTimeZone,
    });
  }

  /**
   * Pure function to calculate slots given the input constraints.
   * This is entirely decoupled from Prisma or external services.
   */
  static calculatePureSlots({
    dateStr,
    eventType,
    availability,
    bookings,
  }: {
    dateStr: string;
    eventType: {
      duration_mins: number;
      buffer_before_mins: number;
      buffer_after_mins: number;
    };
    availability: {
      start_time: string;
      end_time: string;
      timezone: string;
    };
    bookings: {
      start_time: Date;
      end_time: Date;
    }[];
    requestedTimeZone: string;
  }): Slot[] {
    const workStartUTC = DateUtils.parseTimeInTimezone(
      dateStr,
      availability.start_time,
      availability.timezone,
    );
    const workEndUTC = DateUtils.parseTimeInTimezone(
      dateStr,
      availability.end_time,
      availability.timezone,
    );

    const candidateSlots = DateUtils.generateIntervals(
      workStartUTC,
      workEndUTC,
      eventType.duration_mins,
    );

    const nowPlus10Mins = addMinutes(new Date(), 10);
    const validSlots: Slot[] = [];

    for (const slot of candidateSlots) {
      if (isBefore(slot.start, nowPlus10Mins)) {
        continue;
      }

      const isOverlapping = bookings.some((b) => {
        const blockedStart = addMinutes(b.start_time, -eventType.buffer_before_mins);
        const blockedEnd = addMinutes(b.end_time, eventType.buffer_after_mins);

        return isBefore(slot.start, blockedEnd) && isAfter(slot.end, blockedStart);
      });

      if (!isOverlapping) {
        validSlots.push({
          startTime: slot.start.toISOString(),
          endTime: slot.end.toISOString(),
          available: true,
        });
      }
    }

    return validSlots;
  }
}
